window.MM = window.MM || {};
window.MM["psych_p2_neuro"] = [
  {q:"Delirium is best defined as which of the following clinical syndromes?",o:["Acute fluctuating disturbance of consciousness and cognition", "Chronic deterioration in intellectual functioning", "Progressive neurodegenerative memory disorder", "Stable impairment of attention without altered awareness"],a:0,e:"Delirium is characterized by an acute onset, fluctuating course, impaired attention, and altered consciousness."},
  {q:"The neurotransmitter deficiency most strongly implicated in the pathophysiology of delirium is:",o:["Dopamine", "Serotonin", "Acetylcholine", "GABA"],a:2,e:"Reduced cholinergic activity and dopaminergic excess are key neurochemical mechanisms in delirium."},
  {q:"Which electrolyte disturbance is a well-recognized precipitating cause of delirium in hospitalized patients?",o:["Hypercalcemia", "Hyponatremia", "Hypermagnesemia", "Hypophosphatemia"],a:1,e:"Hyponatremia commonly causes acute cerebral dysfunction leading to confusion and delirium."},
  {q:"A 72-year-old patient develops acute agitation, disorientation, and visual hallucinations at night after surgery. This presentation most strongly suggests:",o:["Dementia", "Psychotic depression", "Schizophrenia", "Post-operative delirium"],a:3,e:"Acute onset after surgery with fluctuating confusion is typical of postoperative delirium."},
  {q:"Which of the following medications is most commonly associated with precipitating delirium in elderly patients?",o:["Metformin", "Anticholinergic drugs", "Beta blockers", "Statins"],a:1,e:"Drugs with anticholinergic properties impair acetylcholine transmission, predisposing to delirium."},
  {q:"Alcohol withdrawal delirium (delirium tremens) usually occurs:",o:["48–72 hours after cessation of alcohol", "Immediately after drinking alcohol", "After several months of abstinence", "Only during intoxication"],a:0,e:"Delirium tremens classically develops 2–3 days after stopping alcohol."},
  {q:"Which infection is particularly known to precipitate delirium in elderly hospitalized patients?",o:["Viral hepatitis", "Tuberculosis", "Influenza", "Urinary tract infection"],a:3,e:"UTIs frequently trigger acute delirium in elderly individuals."},
  {q:"Which metabolic condition may present with acute delirium in hospitalized patients?",o:["Hypothyroidism", "Hyperglycemia", "Hepatic encephalopathy", "Vitamin C deficiency"],a:2,e:"Liver failure leads to ammonia accumulation and encephalopathy presenting as delirium."},
  {q:"Which vitamin deficiency is classically associated with delirium and Wernicke’s encephalopathy?",o:["Thiamine deficiency", "Vitamin B12 deficiency", "Vitamin D deficiency", "Vitamin K deficiency"],a:0,e:"Thiamine deficiency causes Wernicke’s encephalopathy presenting with confusion, ataxia, and ophthalmoplegia."},
  {q:"Hypoxia leading to reduced cerebral oxygenation commonly results in:",o:["Depression", "Delirium", "Mania", "Anxiety disorder"],a:1,e:"Reduced cerebral oxygen supply leads to acute brain dysfunction and delirium."},
  {q:"Which of the following endocrine disorders can precipitate delirium?",o:["Hypothyroidism", "Hyperparathyroidism", "Diabetes insipidus", "Thyrotoxicosis"],a:3,e:"Severe thyrotoxicosis can cause agitation, confusion, and delirium."},
  {q:"Delirium occurring in patients with severe infection and systemic inflammatory response is often termed:",o:["Septic delirium", "Toxic psychosis", "Stress reaction", "Adjustment disorder"],a:2,e:"Systemic infection and cytokine release may cause acute encephalopathy and delirium."},
  {q:"The most prominent cognitive deficit in delirium is impairment of:",o:["Long-term memory", "Attention", "Language comprehension", "Abstract reasoning"],a:1,e:"Inattention is the hallmark cognitive deficit in delirium."},
  {q:"Which sleep disturbance is commonly observed in delirium?",o:["Hypersomnia with prolonged sleep", "Normal sleep cycle", "Increased REM sleep only", "Sleep-wake cycle reversal"],a:0,e:"Patients often become drowsy during day and agitated at night."},
  {q:"Visual hallucinations in delirium are typically:",o:["Absent", "Rare", "Vivid and well-formed", "Only auditory"],a:2,e:"Visual hallucinations of animals, people, or objects are common."},
  {q:"A key clinical feature distinguishing delirium from dementia is:",o:["Progressive course", "Memory loss", "Language impairment", "Fluctuating level of consciousness"],a:3,e:"Consciousness is usually impaired and fluctuating in delirium, but preserved in early dementia."},
  {q:"Which orientation is most commonly impaired early in delirium?",o:["Time", "Person", "Language", "Identity"],a:0,e:"Disorientation to time occurs earliest, followed by place and person."},
  {q:"The psychomotor subtype characterized by agitation, restlessness, and hallucinations is:",o:["Hypoactive delirium", "Hyperactive delirium", "Mixed dementia", "Catatonia"],a:1,e:"Hyperactive delirium presents with agitation and hallucinations."},
  {q:"Which subtype of delirium is frequently underdiagnosed because the patient appears quiet and withdrawn?",o:["Hyperactive delirium", "Psychotic delirium", "Mixed delirium", "Hypoactive delirium"],a:3,e:"Hypoactive delirium causes lethargy and reduced activity, often missed clinically."},
  {q:"Perceptual disturbance commonly observed in delirium includes:",o:["True delusion formation", "Illusions", "Obsessive thoughts", "Depersonalization"],a:2,e:"Misinterpretation of real stimuli (illusions) is common in delirium."},
  {q:"Which feature is typical of the course of delirium?",o:["Fluctuation during the day", "Progressive decline over years", "Sudden remission within minutes", "Completely stable symptoms"],a:0,e:"Symptoms often worsen at night (sundowning)."},
  {q:"A delirious patient believes the nurse is a family member. This phenomenon is:",o:["Delusion", "Hallucination", "Confabulation", "Misidentification"],a:3,e:"Delirium commonly involves misidentification of familiar individuals."},
  {q:"Memory impairment in delirium most commonly affects:",o:["Remote memory", "Immediate and recent memory", "Semantic memory", "Procedural memory"],a:1,e:"Short-term memory and attention are primarily impaired."},
  {q:"Emotional disturbances commonly seen in delirium include:",o:["Persistent apathy", "Emotional lability", "Complete emotional absence", "Fixed mood state"],a:2,e:"Patients may rapidly shift between fear, anxiety, anger, or sadness."},
  {q:"The phenomenon of worsening confusion in evening hours in delirium is known as:",o:["Twilight syndrome", "Sundowning", "REM disorder", "Circadian reversal"],a:1,e:"Delirium symptoms often intensify in evening or night."},
  {q:"The most important first step in management of delirium is:",o:["Identify and treat underlying cause", "Start antidepressants", "Long-term antipsychotics", "Immediate ECT"],a:0,e:"Treating the precipitating medical condition is essential."},
  {q:"The antipsychotic most commonly used for acute agitation in delirium is:",o:["Olanzapine", "Quetiapine", "Haloperidol", "Clozapine"],a:2,e:"Haloperidol is preferred because it causes minimal respiratory depression."},
  {q:"Benzodiazepines are specifically indicated in delirium caused by:",o:["Head injury", "Infection", "Metabolic imbalance", "Alcohol withdrawal"],a:3,e:"Benzodiazepines treat withdrawal-related hyperexcitability."},
  {q:"Which non-pharmacological measure is essential in delirium management?",o:["Orientation with clocks and calendars", "Strict isolation", "Sleep deprivation", "Sensory deprivation"],a:0,e:"Environmental orientation helps reduce confusion and agitation."},
  {q:"Excessive environmental stimulation in delirium should be:",o:["Encouraged", "Minimized", "Ignored", "Increased at night"],a:1,e:"Calm surroundings help prevent agitation and confusion."},
  {q:"Which investigation is often necessary to exclude metabolic causes of delirium?",o:["ECG", "Chest X-ray", "Urinalysis", "Serum electrolytes"],a:3,e:"Electrolyte imbalance is a common reversible cause."},
  {q:"Adequate hydration in delirious patients is important because dehydration:",o:["Has no effect on cognition", "Improves alertness", "Worsens delirium", "Prevents hallucinations"],a:2,e:"Dehydration contributes to metabolic disturbances and confusion."},
  {q:"Which approach is recommended when managing agitation in delirium before medications are used?",o:["Verbal reassurance and reorientation", "Immediate sedation", "Physical restraints", "Ignore agitation"],a:0,e:"Non-drug methods are first-line interventions."},
  {q:"Continuous physical restraints in delirium should be:",o:["Routine treatment", "Avoided whenever possible", "First-line therapy", "Used indefinitely"],a:1,e:"Restraints may increase agitation and injury risk."},
  {q:"Low-dose antipsychotics are preferred in delirium primarily to:",o:["Cure delirium", "Improve sleep only", "Control severe agitation and psychosis", "Prevent infection"],a:2,e:"They help manage dangerous behavioral symptoms."},
  {q:"Which complication must be monitored when using haloperidol in delirium?",o:["Hyperglycemia", "Renal failure", "QT prolongation", "Hypercalcemia"],a:3,e:"Haloperidol can prolong QT interval leading to arrhythmias."},
  {q:"Early mobilization in hospitalized patients helps prevent:",o:["Anxiety disorders", "Delirium", "Mania", "Phobias"],a:1,e:"Immobility increases risk of hospital-associated delirium."},
  {q:"Sensory aids such as glasses and hearing aids should be:",o:["Encouraged and provided", "Removed", "Restricted", "Avoided"],a:0,e:"Sensory deprivation worsens confusion."},
  {q:"Which sleep-promoting strategy is recommended in delirium prevention?",o:["Sedation during daytime", "Continuous bright light", "Sleep deprivation", "Maintaining regular sleep schedule"],a:3,e:"Regular sleep cycles reduce delirium risk."},
  {q:"Which monitoring tool is commonly used for detecting delirium in hospitalized patients?",o:["HAM-D scale", "MMSE", "Confusion Assessment Method (CAM)", "Beck Depression Inventory"],a:2,e:"CAM is a validated screening tool for delirium."},
  {q:"Which risk factor strongly predisposes elderly patients to delirium during hospitalization?",o:["Advanced age", "Male gender", "Tall stature", "Athletic activity"],a:0,e:"Aging brain has reduced physiological reserve, increasing delirium risk."},
  {q:"Which neurotransmitter excess is believed to contribute to delirium symptoms?",o:["Acetylcholine", "GABA", "Dopamine", "Glycine"],a:2,e:"Dopaminergic excess contributes to hallucinations and agitation."},
  {q:"Which cognitive function is least affected early in delirium?",o:["Attention", "Remote memory", "Orientation", "Perception"],a:1,e:"Remote memory often remains relatively preserved initially."},
  {q:"Delirium developing within hours after major surgery is most commonly due to:",o:["Depression", "Chronic dementia", "Schizophrenia", "Acute metabolic or physiological stress"],a:3,e:"Surgical stress, anesthesia, and metabolic changes can trigger delirium."},
  {q:"Which preventive strategy significantly reduces delirium incidence in ICU patients?",o:["Multicomponent orientation protocols", "High-dose sedatives", "Sleep deprivation", "Continuous restraints"],a:0,e:"Orientation, mobility, hydration, and sleep hygiene reduce delirium risk."},
  {q:"Which drug class should generally be avoided in elderly patients at risk for delirium?",o:["Antihypertensives", "Anticholinergics", "Proton pump inhibitors", "Vitamin supplements"],a:1,e:"Anticholinergics impair cognition and increase delirium risk."},
  {q:"Hypoactive delirium is often mistaken clinically for:",o:["Mania", "Schizophrenia", "Depression", "Panic disorder"],a:2,e:"Lethargy and withdrawal resemble depressive symptoms."},
  {q:"Which investigation is essential when infection is suspected as a cause of delirium?",o:["EEG", "MRI", "PET scan", "Blood culture"],a:3,e:"Identifying infectious causes allows targeted treatment."},
  {q:"Which clinical feature is most useful in distinguishing delirium from primary psychosis?",o:["Auditory hallucinations", "Impaired attention", "Delusions", "Agitation"],a:1,e:"Attention deficit is core to delirium but uncommon in psychosis."},
  {q:"Which environmental modification is beneficial in delirium management?",o:["Adequate lighting", "Dark isolation room", "Loud surroundings", "Rotating caregivers hourly"],a:0,e:"Proper lighting reduces illusions and confusion."},
  {q:"Delirium lasting several weeks despite treatment should prompt evaluation for:",o:["Anxiety disorder", "Personality disorder", "Conversion disorder", "Underlying dementia"],a:3,e:"Persistent delirium may unmask preexisting dementia."},
  {q:"EEG findings in delirium typically show:",o:["Increased beta activity", "Normal pattern", "Diffuse slowing", "Epileptiform spikes only"],a:2,e:"Generalized slowing reflects global cerebral dysfunction."},
  {q:"The most effective preventive measure for delirium in hospitalized elderly patients is:",o:["Early recognition of risk factors", "Routine antipsychotics", "Sedation therapy", "Bed rest"],a:0,e:"Prevention strategies target modifiable risk factors."},
  {q:"Which clinical course best characterizes delirium?",o:["Chronic progressive", "Acute and reversible", "Lifelong condition", "Fixed neurological deficit"],a:1,e:"Delirium is usually transient if the cause is treated."},
  {q:"Delirium secondary to severe infection is most commonly associated with:",o:["Increased serotonin", "Dopamine depletion", "Reduced GABA", "Inflammatory cytokine release"],a:3,e:"Systemic inflammation affects brain function and cognition."},
  {q:"Which group is at highest risk for hospital-acquired delirium?",o:["Young adults", "Middle-aged workers", "Elderly with multiple comorbidities", "Athletes"],a:2,e:"Age, illness, and polypharmacy increase vulnerability."},
  {q:"Which clinical finding strongly suggests delirium rather than dementia?",o:["Gradual memory loss", "Rapid onset confusion", "Progressive cognitive decline", "Long disease duration"],a:1,e:"Delirium has sudden onset, unlike dementia."},
  {q:"In delirium management, family presence is helpful because it:",o:["Improves orientation", "Causes agitation", "Worsens hallucinations", "Delays recovery"],a:0,e:"Familiar faces help reduce anxiety and confusion."},
  {q:"Which feature is least typical of delirium?",o:["Fluctuating cognition", "Disturbed sleep cycle", "Stable consciousness", "Impaired attention"],a:2,e:"Consciousness usually fluctuates in delirium."},
  {q:"The prognosis of delirium primarily depends on:",o:["Patient gender", "Hospital environment", "Duration of hospitalization", "Treatment of the underlying cause"],a:3,e:"Successful management of the precipitating illness determines recovery."},
  {q:"A 74-year-old man is admitted with pneumonia. On the third hospital day he becomes confused, disoriented, and attempts to remove his IV line. At times he is lucid but later becomes agitated and reports seeing animals crawling on the wall. Which feature most strongly supports delirium rather than acute psychosis?",o:["Presence of visual hallucinations", "Fluctuating level of consciousness", "Presence of agitation", "Presence of delusional ideas"],a:1,e:"A fluctuating course with impaired consciousness and attention is a hallmark feature distinguishing delirium from primary psychosis."},
  {q:"A 79-year-old woman with hip fracture surgery becomes quiet, withdrawn, and slow to respond. She appears sleepy, answers questions briefly, and shows reduced motor activity. Nurses initially suspect depression. Which diagnosis is most likely?",o:["Major depressive episode", "Catatonia", "Hypoactive delirium", "Early dementia"],a:2,e:"Hypoactive delirium presents with lethargy, decreased motor activity, and reduced responsiveness, often mistaken for depression."},
  {q:"A hospitalized patient suddenly becomes confused and inattentive. When asked to count backward from 20, he repeatedly loses track and cannot maintain focus. Which cognitive domain is primarily impaired?",o:["Executive function", "Language comprehension", "Attention", "Remote memory"],a:2,e:"Impaired attention is the most consistent and earliest cognitive deficit in delirium."},
  {q:"A 68-year-old chronic alcoholic is admitted with tremors and agitation two days after stopping alcohol. He becomes disoriented, sweaty, tachycardic, and reports seeing insects crawling on the bed. What is the most appropriate first-line pharmacological treatment?",o:["Haloperidol", "Diazepam", "Fluoxetine", "Lithium"],a:1,e:"Benzodiazepines are first-line treatment for delirium tremens because they control withdrawal-related CNS hyperexcitability."},
  {q:"An elderly ICU patient becomes delirious at night with agitation and hallucinations. The physician decides to start haloperidol. Which complication must be carefully monitored during treatment?",o:["QT interval prolongation", "Severe hyperglycemia", "Renal failure", "Hypothyroidism"],a:0,e:"Haloperidol can prolong QT interval and increase risk of arrhythmias, requiring monitoring."},
  {q:"A 75-year-old man with mild dementia develops sudden confusion after starting oxybutynin for urinary incontinence. What is the most likely mechanism causing his delirium?",o:["Excess GABA activity", "Cholinergic excess", "Anticholinergic effect reducing acetylcholine", "Serotonin depletion"],a:2,e:"Anticholinergic drugs reduce acetylcholine transmission, which plays a key role in delirium pathophysiology."},
  {q:"A hospitalized patient with delirium repeatedly tries to climb out of bed and remove medical devices despite reassurance. Non-pharmacological measures fail. Which medication is most appropriate for controlling severe agitation?",o:["Clozapine", "Haloperidol", "Amitriptyline", "Carbamazepine"],a:1,e:"Low-dose haloperidol is commonly used to manage severe agitation in delirium when behavioral strategies fail."},
  {q:"A confused elderly patient misinterprets the pattern on a curtain as snakes moving toward him. Which perceptual disturbance is demonstrated?",o:["Delusion", "Hallucination", "Illusion", "Depersonalization"],a:2,e:"Illusions are misinterpretations of real external stimuli, common in delirium."},
  {q:"A 72-year-old hospitalized patient becomes acutely confused and inattentive. Laboratory evaluation shows sodium level of 118 mmol/L. Which mechanism best explains the neurological symptoms?",o:["Acute neuronal dehydration", "Cerebral edema from osmotic imbalance", "Increased dopamine synthesis", "Reduced cerebral blood flow"],a:1,e:"Severe hyponatremia causes osmotic shifts leading to cerebral edema and delirium."},
  {q:"An elderly patient with delirium becomes more confused and agitated every evening despite improvement during the day. What phenomenon best explains this pattern?",o:["Catatonic fluctuation", "Rapid cycling mood disorder", "Sundowning", "REM behavior disorder"],a:2,e:"Evening worsening of confusion and agitation is characteristic of delirium and dementia-related sundowning."},
  {q:"Dementia is best defined as which of the following clinical conditions?",o:["Acute reversible disturbance of consciousness", "Chronic progressive decline in multiple cognitive domains with preserved consciousness", "Sudden impairment of attention with hallucinations", "Temporary loss of memory after trauma"],a:1,e:"Dementia involves gradual deterioration of cognition with preserved consciousness."},
  {q:"According to modern classification, dementia is most accurately categorized under which group of disorders?",o:["Mood disorders", "Anxiety disorders", "Neurocognitive disorders", "Somatoform disorders"],a:2,e:"DSM-5 places dementia under Major Neurocognitive Disorders."},
  {q:"Which cognitive domain is typically affected earliest in Alzheimer’s disease?",o:["Procedural memory", "Episodic memory", "Language comprehension", "Motor coordination"],a:1,e:"Early Alzheimer’s disease primarily affects recent episodic memory."},
  {q:"The most common cause of dementia worldwide is:",o:["Parkinson’s disease dementia", "Frontotemporal dementia", "Alzheimer’s disease", "Vascular dementia"],a:2,e:"Alzheimer’s disease accounts for about 60–70% of dementia cases."},
  {q:"Which pathological protein forms extracellular plaques in Alzheimer’s disease?",o:["Tau protein", "Alpha-synuclein", "Beta-amyloid", "Huntingtin"],a:2,e:"Beta-amyloid accumulation forms characteristic plaques."},
  {q:"Neurofibrillary tangles in Alzheimer’s disease are composed mainly of:",o:["Hyperphosphorylated tau protein", "Dopamine aggregates", "Alpha-synuclein", "Amyloid precursor protein"],a:0,e:"Abnormal tau disrupts neuronal microtubules."},
  {q:"The earliest brain region affected in Alzheimer’s disease is usually:",o:["Cerebellum", "Hippocampus", "Occipital cortex", "Brainstem"],a:1,e:"Hippocampal degeneration causes early memory loss."},
  {q:"A 70-year-old patient shows gradual memory loss, difficulty recalling recent conversations, and misplacing objects but retains social behavior. Which stage of Alzheimer’s disease is most likely?",o:["Early stage", "Late stage", "Terminal stage", "Psychotic stage"],a:0,e:"Early disease shows mild episodic memory impairment."},
  {q:"The major neurotransmitter deficiency implicated in Alzheimer’s disease is:",o:["Dopamine", "Acetylcholine", "Serotonin", "GABA"],a:1,e:"Degeneration of cholinergic neurons contributes to symptoms."},
  {q:"Which genetic factor is strongly associated with late-onset Alzheimer’s disease?",o:["APOE ε4 allele", "BRCA1 mutation", "HLA-B27 gene", "CFTR mutation"],a:0,e:"APOE-ε4 significantly increases Alzheimer’s risk."},
  {q:"Early-onset familial Alzheimer’s disease is most often associated with mutations in:",o:["Presenilin genes", "Dopamine receptor genes", "Serotonin transporter genes", "Myelin genes"],a:0,e:"Mutations in PSEN1, PSEN2, and APP cause familial Alzheimer’s."},
  {q:"A patient with Alzheimer’s disease gradually develops aphasia, apraxia, and agnosia. This pattern represents impairment of:",o:["Cortical association areas", "Cerebellar circuits", "Basal ganglia pathways", "Brainstem nuclei"],a:0,e:"Cortical degeneration causes language and recognition deficits."},
  {q:"Which symptom is most typical of moderate Alzheimer’s disease?",o:["Mild forgetfulness only", "Difficulty performing daily tasks", "Complete immobility", "Persistent coma"],a:1,e:"Functional impairment appears during the moderate stage."},
  {q:"Behavioral symptoms frequently seen in Alzheimer’s disease include:",o:["Apathy and irritability", "Hyperreflexia", "Severe tremors", "Ataxia"],a:0,e:"Behavioral and psychological symptoms are common."},
  {q:"The hallmark imaging finding in Alzheimer’s disease is:",o:["Diffuse cortical atrophy with hippocampal shrinkage", "Pontine infarction", "Cerebellar hypertrophy", "Brainstem lesions"],a:0,e:"MRI commonly shows temporal lobe and hippocampal atrophy."},
  {q:"Vascular dementia is primarily caused by:",o:["Neurodegenerative protein accumulation", "Chronic cerebral ischemia", "Autoimmune demyelination", "Viral infection"],a:1,e:"Reduced blood supply damages brain tissue."},
  {q:"The typical clinical course of vascular dementia is:",o:["Gradual steady decline", "Stepwise deterioration", "Rapid recovery", "Cyclic symptoms"],a:1,e:"Cognitive decline often follows repeated strokes."},
  {q:"The most common risk factor for vascular dementia is:",o:["Hypertension", "Asthma", "Thyroid disease", "Migraine"],a:0,e:"Hypertension leads to cerebrovascular damage."},
  {q:"Which pathology is commonly seen in vascular dementia?",o:["Multiple cerebral infarcts", "Beta-amyloid plaques only", "Lewy bodies", "Demyelination plaques"],a:0,e:"Multiple infarcts disrupt cognitive networks."},
  {q:"Compared with Alzheimer’s disease, vascular dementia more often shows:",o:["Early personality changes", "Early memory loss", "Focal neurological deficits", "Early hallucinations"],a:2,e:"Stroke-related deficits such as hemiparesis may occur."},
  {q:"Which imaging modality best demonstrates infarcts causing vascular dementia?",o:["MRI brain", "Skull X-ray", "Ultrasound abdomen", "ECG"],a:0,e:"MRI is sensitive for small infarcts and white-matter lesions."},
  {q:"A patient develops cognitive decline after several transient ischemic attacks. Which diagnosis is most likely?",o:["Alzheimer’s dementia", "Vascular dementia", "Lewy body dementia", "Frontotemporal dementia"],a:1,e:"Repeated TIAs can lead to vascular cognitive impairment."},
  {q:"The pathology most associated with lacunar infarcts in vascular dementia is:",o:["Small vessel disease", "Viral encephalitis", "Autoimmune vasculitis", "Tumor metastasis"],a:0,e:"Hypertension causes lipohyalinosis of small vessels."},
  {q:"Which symptom often appears earlier in vascular dementia than in Alzheimer’s disease?",o:["Memory impairment", "Executive dysfunction", "Aphasia", "Apraxia"],a:1,e:"Frontal-subcortical circuits controlling planning are affected early."},
  {q:"A patient with dementia shows sudden cognitive worsening after a stroke. What is the most likely explanation?",o:["Neurodegenerative acceleration", "Acute vascular injury", "Viral infection", "Psychiatric disorder"],a:1,e:"A new infarct produces abrupt cognitive decline."},
  {q:"Amnestic syndrome primarily involves impairment of:",o:["Motor coordination", "Language", "Memory", "Vision"],a:2,e:"The core deficit is impaired memory formation and recall."},
  {q:"The classic cause of amnestic syndrome in chronic alcoholism is:",o:["Vitamin B6 deficiency", "Thiamine deficiency", "Vitamin C deficiency", "Iron deficiency"],a:1,e:"Thiamine deficiency leads to Korsakoff syndrome."},
  {q:"Korsakoff syndrome typically presents with:",o:["Severe hallucinations", "Confabulation and memory loss", "Hyperactivity", "Tremors"],a:1,e:"Patients fabricate stories to fill memory gaps."},
  {q:"The brain region most affected in Korsakoff syndrome is:",o:["Mammillary bodies", "Cerebellum", "Occipital cortex", "Basal ganglia"],a:0,e:"Damage disrupts the limbic memory circuit."},
  {q:"Anterograde amnesia refers to inability to:",o:["Recall childhood events", "Form new memories", "Recognize faces", "Understand language"],a:1,e:"New information cannot be encoded into memory."},
  {q:"Retrograde amnesia involves loss of:",o:["Future memory", "Motor skills", "Previously formed memories", "Attention"],a:2,e:"It affects memories formed before the event."},
  {q:"Which condition commonly produces transient global amnesia?",o:["Migraine or vascular dysfunction", "Diabetes", "Asthma", "Kidney disease"],a:0,e:"Vascular disturbances are commonly implicated."},
  {q:"Which neurotransmitter system is targeted by drugs used to treat Alzheimer’s disease?",o:["Cholinergic system", "Dopaminergic system", "Histaminergic system", "Adrenergic system"],a:0,e:"Cholinesterase inhibitors increase acetylcholine."},
  {q:"Donepezil primarily acts by:",o:["Blocking dopamine receptors", "Inhibiting acetylcholinesterase", "Increasing serotonin release", "Blocking NMDA receptors"],a:1,e:"This increases synaptic acetylcholine levels."},
  {q:"Memantine used in Alzheimer’s disease acts on:",o:["NMDA glutamate receptors", "Dopamine receptors", "GABA receptors", "Serotonin receptors"],a:0,e:"It reduces glutamate-mediated excitotoxicity."},
  {q:"Which dementia often presents with early personality change and disinhibition?",o:["Alzheimer’s disease", "Vascular dementia", "Frontotemporal dementia", "Parkinson’s dementia"],a:2,e:"Frontal lobe degeneration causes behavioral changes."},
  {q:"A patient with dementia develops visual hallucinations and parkinsonism. Which diagnosis is most likely?",o:["Alzheimer’s dementia", "Lewy body dementia", "Vascular dementia", "Korsakoff syndrome"],a:1,e:"Hallucinations and parkinsonism are typical."},
  {q:"Which pathological inclusion characterizes Lewy body dementia?",o:["Beta-amyloid plaques", "Tau tangles", "Alpha-synuclein inclusions", "Demyelinating plaques"],a:2,e:"Lewy bodies contain alpha-synuclein protein."},
  {q:"Which feature distinguishes Lewy body dementia from Alzheimer’s disease?",o:["Early memory loss", "Fluctuating cognition with hallucinations", "Severe aphasia", "Stepwise progression"],a:1,e:"Fluctuating cognition and hallucinations are key features."},
  {q:"A patient with dementia becomes extremely sensitive to antipsychotics and develops rigidity. Which dementia should be suspected?",o:["Alzheimer’s dementia", "Vascular dementia", "Lewy body dementia", "Frontotemporal dementia"],a:2,e:"Neuroleptic sensitivity is characteristic."},
  {q:"Which lifestyle factor significantly increases risk for vascular dementia?",o:["Smoking", "High vitamin intake", "Physical exercise", "Balanced diet"],a:0,e:"Smoking accelerates vascular disease."},
  {q:"The Mini-Mental State Examination primarily assesses:",o:["Motor reflexes", "Cognitive function", "Emotional intelligence", "Visual acuity"],a:1,e:"It screens memory, attention, and orientation."},
  {q:"A patient with Alzheimer’s disease begins wandering and forgetting family members. Which stage is most consistent?",o:["Early stage", "Mild stage", "Moderate stage", "Terminal stage"],a:2,e:"Disorientation and behavioral disturbance appear in moderate disease."},
  {q:"Severe Alzheimer’s disease commonly leads to:",o:["Preserved independence", "Total dependence for daily activities", "Complete recovery", "Normal cognition"],a:1,e:"Advanced disease causes severe functional loss."},
  {q:"Which cognitive test specifically assesses attention in dementia screening?",o:["Serial sevens test", "Drawing test", "Finger tapping test", "Gait analysis"],a:0,e:"It evaluates attention and concentration."},
  {q:"Which pathology correlates most closely with cognitive severity in Alzheimer’s disease?",o:["Number of amyloid plaques", "Amount of tau tangles", "Degree of infarcts", "Dopamine levels"],a:1,e:"Neurofibrillary tangle burden correlates strongly with severity."},
  {q:"Which cognitive deficit commonly appears early in vascular dementia?",o:["Aphasia", "Executive dysfunction", "Prosopagnosia", "Apraxia"],a:1,e:"Frontal-subcortical circuits controlling planning are affected."},
  {q:"A patient with dementia suddenly worsens after hypotensive shock. Which mechanism explains the decline?",o:["Cerebral hypoperfusion", "Neurotransmitter excess", "Viral invasion", "Hormonal imbalance"],a:0,e:"Reduced blood flow damages neurons."},
  {q:"Which preventive strategy reduces risk of vascular dementia?",o:["Blood pressure control", "Sleep deprivation", "Smoking", "High-fat diet"],a:0,e:"Controlling hypertension prevents vascular damage."},
  {q:"Which symptom is most characteristic of Korsakoff syndrome?",o:["Severe motor weakness", "Confabulation", "Tremors", "Visual hallucinations"],a:1,e:"Fabricated stories fill gaps in memory."},
  {q:"Damage to which brain structure most severely disrupts memory consolidation?",o:["Hippocampus", "Cerebellum", "Medulla", "Pons"],a:0,e:"Hippocampus is essential for memory encoding."},
  {q:"Which dementia progresses most rapidly?",o:["Alzheimer’s disease", "Vascular dementia", "Creutzfeldt-Jakob disease", "Frontotemporal dementia"],a:2,e:"Prion disease causes rapidly progressive dementia."},
  {q:"A patient develops urinary incontinence, gait disturbance, and cognitive decline. Which condition should be suspected?",o:["Alzheimer’s disease", "Normal pressure hydrocephalus", "Vascular dementia", "Lewy body dementia"],a:1,e:"Classic triad: gait disturbance, dementia, urinary incontinence."},
  {q:"Which test is most useful for diagnosing Alzheimer’s disease definitively?",o:["CT scan", "MRI", "Clinical assessment with supportive imaging", "EEG"],a:2,e:"Diagnosis is primarily clinical."},
  {q:"Which symptom appears earliest in Korsakoff syndrome?",o:["Confabulation", "Severe motor weakness", "Anterograde amnesia", "Delirium"],a:2,e:"Inability to form new memories is the key deficit."},
  {q:"Which neurotransmitter deficit contributes to behavioral symptoms in dementia?",o:["Serotonin", "Dopamine", "Acetylcholine", "Norepinephrine"],a:0,e:"Serotonergic dysfunction contributes to mood symptoms."},
  {q:"Which brain region degenerates predominantly in frontotemporal dementia?",o:["Frontal and temporal lobes", "Cerebellum", "Brainstem", "Occipital cortex"],a:0,e:"Degeneration causes personality and language disturbances."},
  {q:"A patient shows preserved memory but severe language impairment and word-finding difficulty. Which disorder is likely?",o:["Alzheimer’s disease", "Primary progressive aphasia", "Vascular dementia", "Korsakoff syndrome"],a:1,e:"A language-dominant subtype of frontotemporal dementia."},
  {q:"Which dementia is most strongly linked to repeated head trauma?",o:["Alzheimer’s disease", "Vascular dementia", "Chronic traumatic encephalopathy", "Korsakoff syndrome"],a:2,e:"Repeated brain injury leads to tau deposition."},
  {q:"The prognosis of most neurodegenerative dementias is:",o:["Complete recovery", "Stable cognition", "Progressive deterioration", "Rapid cure with medication"],a:2,e:"Neurodegenerative dementias show gradual irreversible decline."},
  {q:"A 68-year-old retired teacher is brought by family due to progressive forgetfulness over 2 years. She repeatedly asks the same questions, misplaces household objects, and struggles to recall recent conversations. Neurological examination is otherwise normal. MRI shows hippocampal atrophy. What is the most likely underlying pathological process?",o:["Beta-amyloid plaque deposition with tau neurofibrillary tangles", "Alpha-synuclein inclusions in brainstem nuclei", "Multiple lacunar infarctions in basal ganglia", "Demyelination of cerebral white matter"],a:0,e:"Alzheimer’s disease involves amyloid plaque accumulation and tau neurofibrillary tangles, especially affecting the hippocampus."},
  {q:"A 72-year-old man with long-standing hypertension and diabetes develops cognitive decline over several years. His family reports sudden worsening of memory and executive function after each minor stroke. Neurological examination reveals mild left-sided weakness. Which diagnosis best explains this pattern?",o:["Alzheimer’s disease", "Frontotemporal dementia", "Vascular dementia", "Lewy body dementia"],a:2,e:"Stepwise deterioration with focal neurological deficits following strokes suggests vascular dementia."},
  {q:"A 65-year-old patient presents with progressive personality change, disinhibition, inappropriate jokes, and lack of social awareness over 1 year. Memory remains relatively preserved in early stages. MRI shows frontal lobe atrophy. Which diagnosis is most likely?",o:["Alzheimer’s disease", "Vascular dementia", "Lewy body dementia", "Frontotemporal dementia"],a:3,e:"Early behavioral changes and frontal lobe degeneration are typical of frontotemporal dementia."},
  {q:"A 70-year-old man presents with progressive memory loss and confusion. During examination he is unable to learn three new words after repeated attempts but recalls childhood memories clearly. Which memory process is primarily impaired?",o:["Procedural memory", "Working memory", "Anterograde memory formation", "Semantic memory"],a:2,e:"Alzheimer’s disease initially impairs the ability to form new memories."},
  {q:"A 74-year-old woman with dementia reports seeing children playing in her room despite no one being present. She also has fluctuating cognition and mild parkinsonian rigidity. Which diagnosis is most consistent with this presentation?",o:["Alzheimer’s disease", "Vascular dementia", "Lewy body dementia", "Korsakoff syndrome"],a:2,e:"Visual hallucinations, fluctuating cognition, and parkinsonism strongly suggest Lewy body dementia."},
  {q:"A 58-year-old chronic alcoholic presents with severe memory impairment. He is unable to recall events from the previous day but confidently invents detailed stories when questioned. Which mechanism best explains this behavior?",o:["Delusional belief formation", "Confabulation due to memory circuit damage", "Hallucinatory perception", "Language comprehension deficit"],a:1,e:"Korsakoff syndrome causes confabulation to compensate for severe memory deficits."},
  {q:"A 69-year-old patient presents with progressive cognitive impairment and difficulty planning tasks such as managing finances and organizing daily activities. Memory is relatively preserved early. MRI shows extensive subcortical white matter ischemic changes. Which cognitive domain is primarily affected?",o:["Executive function", "Language comprehension", "Visual perception", "Motor coordination"],a:0,e:"Vascular dementia commonly affects frontal-subcortical circuits responsible for executive function."},
  {q:"A 75-year-old man with mild cognitive impairment suddenly develops worsening confusion after severe hypotension during surgery. Brain imaging later reveals diffuse watershed infarcts. What is the most likely mechanism for his cognitive decline?",o:["Beta-amyloid accumulation", "Chronic inflammation", "Cerebral hypoperfusion", "Dopamine deficiency"],a:2,e:"Severe hypotension causes global cerebral ischemia leading to cognitive decline."},
  {q:"A 62-year-old patient develops progressive language difficulty, with inability to name objects and frequent word-finding pauses. Memory and behavior remain relatively intact initially. Which diagnosis best explains this presentation?",o:["Alzheimer’s disease", "Primary progressive aphasia", "Vascular dementia", "Lewy body dementia"],a:1,e:"A subtype of frontotemporal dementia affecting language-dominant cortical regions."},
  {q:"A 71-year-old man presents with gait disturbance, urinary urgency, and progressive cognitive decline. Brain imaging shows enlarged ventricles without cortical atrophy. Which mechanism best explains the cognitive impairment?",o:["Neurodegenerative tau deposition", "Ventricular enlargement compressing frontal pathways", "Amyloid plaque accumulation", "Demyelination of spinal tracts"],a:1,e:"Normal pressure hydrocephalus causes ventricular dilation affecting frontal lobe circuits responsible for cognition and gait."},
  {q:"A 67-year-old man is brought by his family due to progressive forgetfulness over 3 years. He frequently forgets recent conversations but vividly recalls events from decades ago. MRI reveals marked atrophy of the medial temporal lobes. Which structure is primarily responsible for this patient’s memory deficit?",o:["Hippocampus", "Cerebellum", "Thalamus", "Pons"],a:0,e:"The hippocampus is essential for formation of new episodic memories, and early degeneration occurs in Alzheimer’s disease."},
  {q:"A 73-year-old woman with long-standing hypertension develops gradual cognitive impairment. Her family reports that her symptoms worsen abruptly after episodes of stroke. On examination she has mild right-sided weakness and brisk reflexes. Which clinical pattern best describes this dementia?",o:["Rapid fluctuating course", "Stepwise cognitive deterioration", "Continuous gradual improvement", "Episodic memory recovery"],a:1,e:"Vascular dementia often progresses in a stepwise fashion following cerebrovascular events."},
  {q:"A 70-year-old patient with Alzheimer’s disease becomes lost in familiar places and cannot recognize close relatives. Which cortical deficit best explains this symptom?",o:["Apraxia", "Aphasia", "Agnosia", "Ataxia"],a:2,e:"Agnosia refers to inability to recognize familiar objects or persons despite intact sensory function."},
  {q:"A 59-year-old former boxer develops progressive cognitive decline, mood instability, and impulsive behavior. Imaging shows diffuse cortical atrophy with tau deposition. Which diagnosis is most consistent with this history?",o:["Alzheimer’s disease", "Chronic traumatic encephalopathy", "Vascular dementia", "Korsakoff syndrome"],a:1,e:"Repeated head trauma leads to tau pathology and progressive neurodegeneration."},
  {q:"A 72-year-old patient with dementia suddenly develops new memory deficits and left-sided weakness after a stroke. Cognitive decline accelerates rapidly. Which mechanism explains the sudden worsening?",o:["Acute neuronal ischemia causing infarction", "Gradual amyloid accumulation", "Progressive tau deposition", "Dopamine receptor loss"],a:0,e:"Vascular dementia may worsen abruptly due to new cerebral infarcts."},
  {q:"A 65-year-old man with chronic alcoholism is unable to recall events from earlier in the day but confidently invents explanations when questioned. MRI shows lesions in the mammillary bodies. Which diagnosis is most likely?",o:["Alzheimer’s disease", "Frontotemporal dementia", "Korsakoff syndrome", "Lewy body dementia"],a:2,e:"Damage to mammillary bodies from thiamine deficiency causes severe memory impairment and confabulation."},
  {q:"A patient with dementia is unable to perform previously learned motor tasks such as using utensils despite intact motor strength. Which cognitive deficit is present?",o:["Apraxia", "Aphasia", "Agnosia", "Amnesia"],a:0,e:"Apraxia is the inability to perform learned motor activities despite intact motor function."},
  {q:"A 74-year-old woman with Alzheimer’s disease develops agitation, wandering behavior, and disrupted sleep-wake cycles. Which brain neurotransmitter deficit contributes most to her cognitive symptoms?",o:["Dopamine deficiency", "Acetylcholine deficiency", "GABA deficiency", "Norepinephrine deficiency"],a:1,e:"Degeneration of cholinergic neurons in the basal forebrain contributes significantly to Alzheimer’s symptoms."},
  {q:"A 69-year-old patient with vascular dementia demonstrates difficulty planning tasks, organizing activities, and making decisions, while memory impairment is relatively mild. Which brain region is most likely involved?",o:["Frontal lobe circuits", "Occipital cortex", "Cerebellum", "Brainstem"],a:0,e:"Vascular lesions affecting frontal-subcortical pathways impair executive function."},
  {q:"A 66-year-old patient presents with progressive memory impairment. PET imaging demonstrates reduced glucose metabolism in the temporoparietal cortex. Which disease process most commonly produces this pattern?",o:["Lewy body dementia", "Vascular dementia", "Alzheimer’s disease", "Korsakoff syndrome"],a:2,e:"Alzheimer’s disease often shows temporoparietal hypometabolism on PET imaging."},
  {q:"A 22-year-old university student suddenly collapses during a football match. Witnesses report that his body became stiff followed by rhythmic jerking of all limbs lasting about two minutes. After the episode he was confused, exhausted, and complained of a headache for nearly 30 minutes. Which phase of the seizure explains his confusion and fatigue after the convulsions ended?",o:["Aura phase", "Interictal phase", "Postictal phase", "Prodromal phase"],a:2,e:"The postictal phase occurs after seizure activity ends and is characterized by confusion, drowsiness, headache, and sometimes temporary neurological deficits. This phase reflects transient neuronal exhaustion and recovery of brain function after abnormal electrical discharge."},
  {q:"A 16-year-old boy frequently experiences sudden brief jerks of both arms early in the morning, especially after sleep deprivation. During these episodes he remains fully conscious but may drop objects from his hands. EEG later reveals generalized polyspike discharges. Which epilepsy syndrome is most consistent with this presentation?",o:["Juvenile myoclonic epilepsy", "Absence epilepsy", "Lennox-Gastaut syndrome", "Temporal lobe epilepsy"],a:0,e:"Juvenile myoclonic epilepsy commonly presents during adolescence with morning myoclonic jerks, often triggered by sleep deprivation. Patients remain conscious, and EEG typically shows generalized polyspike-and-wave patterns."},
  {q:"A 45-year-old patient with focal epilepsy describes episodes beginning with a sudden feeling of fear and a rising sensation in the abdomen, followed by lip-smacking and purposeless hand movements lasting about one minute. He has no recollection of the episode afterward. Which brain region is most likely responsible for this seizure?",o:["Occipital lobe", "Temporal lobe", "Parietal lobe", "Cerebellum"],a:1,e:"Temporal lobe epilepsy commonly presents with epigastric aura, emotional sensations, and automatisms such as lip-smacking. These seizures often involve impaired awareness due to limbic system involvement."},
  {q:"A 30-year-old woman with epilepsy becomes pregnant and asks about continuing treatment. She has been taking valproate for generalized seizures. Why is switching to an alternative medication often recommended in such patients?",o:["Valproate reduces drug effectiveness", "Valproate has high teratogenic risk", "Valproate causes severe hypertension", "Valproate leads to renal failure"],a:1,e:"Valproate is associated with increased risk of neural tube defects and other congenital malformations. Therefore, alternative medications such as lamotrigine or carbamazepine may be considered in women of childbearing age."},
  {q:"A patient with epilepsy suddenly develops continuous generalized convulsions lasting more than 10 minutes without regaining consciousness between episodes. Immediate treatment is required to prevent brain injury. Which medication should be administered first?",o:["Diazepam", "Carbamazepine", "Phenytoin", "Valproate"],a:0,e:"In status epilepticus, benzodiazepines such as diazepam or lorazepam are first-line therapy because they rapidly enhance GABA-mediated inhibition and help terminate ongoing seizure activity."},
  {q:"A 9-year-old child frequently experiences brief episodes of staring lasting about 10 seconds during which he stops responding and blinks repeatedly. Afterward he resumes activity without confusion. Hyperventilation during examination reproduces the event. Which diagnostic test is most helpful for confirming the diagnosis?",o:["MRI brain", "EEG", "CT scan", "Lumbar puncture"],a:1,e:"EEG is crucial in diagnosing absence seizures because it typically demonstrates generalized 3-Hz spike-and-wave discharges, especially when triggered by hyperventilation during testing."},
  {q:"A patient with long-standing epilepsy reports that seizures often occur after nights with little sleep or during periods of intense stress. Which physiological mechanism most likely explains this relationship?",o:["Increased neuronal excitability due to sleep deprivation", "Reduced cerebral blood flow", "Excess serotonin release", "Increased acetylcholine inhibition"],a:0,e:"Sleep deprivation lowers the seizure threshold by increasing cortical neuronal excitability and reducing inhibitory control, making seizures more likely in susceptible individuals."},
  {q:"A 52-year-old man with poorly controlled epilepsy is evaluated for surgery after failing multiple antiepileptic medications. Imaging reveals a localized epileptogenic focus in the temporal lobe. Which principle explains why surgical removal may successfully control his seizures?",o:["Removal of abnormal vascular structures", "Elimination of the seizure-generating focus", "Increased dopamine production", "Reduction of intracranial pressure"],a:1,e:"In drug-resistant focal epilepsy, surgical resection of the epileptogenic focus can prevent abnormal electrical discharges from spreading and may significantly reduce or eliminate seizures."},
  {q:"A patient with epilepsy suddenly collapses without warning due to abrupt loss of muscle tone and immediately regains consciousness. These events occur several times per day and have caused repeated injuries. Which seizure type best explains these episodes?",o:["Myoclonic seizure", "Absence seizure", "Atonic seizure", "Tonic seizure"],a:2,e:"Atonic seizures cause sudden loss of muscle tone, leading to falls or head drops. Because they occur abruptly and without warning, they often result in injuries."},
  {q:"A 28-year-old patient presents after experiencing his first unprovoked seizure. Neurological examination and imaging are normal. Which factor would most strongly increase the risk of seizure recurrence and justify starting long-term antiepileptic therapy?",o:["Family history of migraines", "Abnormal EEG showing epileptiform discharges", "Mild headache after the seizure", "Short duration of seizure"],a:1,e:"The presence of epileptiform activity on EEG significantly increases the likelihood of recurrent seizures and may influence the decision to initiate long-term antiepileptic treatment."},
  {q:"A 28-year-old woman presents with recurrent unilateral throbbing headaches associated with nausea, photophobia, and worsening with physical activity. Each episode lasts about 12 hours and she prefers to lie in a dark room during attacks. Which type of headache is most consistent with this presentation?",o:["Cluster headache", "Migraine without aura", "Tension-type headache", "Sinus headache"],a:1,e:"Migraine without aura typically causes unilateral throbbing pain with nausea, photophobia, and worsening with activity, often lasting several hours."},
  {q:"A 32-year-old man complains of severe stabbing pain around the right eye occurring nightly for two weeks. Each episode lasts about 45 minutes and is associated with tearing and nasal congestion on the same side. What is the most likely diagnosis?",o:["Cluster headache", "Migraine with aura", "Tension headache", "Occipital neuralgia"],a:0,e:"Cluster headaches present with severe unilateral orbital pain with autonomic features such as lacrimation and nasal congestion, typically occurring in clusters over weeks."},
  {q:"A 40-year-old office worker reports dull, bilateral headaches described as a “tight band” around the head, usually occurring after long hours of work and stress. Neurological examination is normal. Which headache type is most likely?",o:["Migraine headache", "Tension-type headache", "Cluster headache", "Trigeminal neuralgia"],a:1,e:"Tension headaches produce bilateral pressure-like pain often related to stress or muscle tension, without nausea or focal neurological symptoms."},
  {q:"A patient with migraine reports seeing flashing lights and zigzag lines before the onset of headache. What is this phenomenon called?",o:["Prodrome", "Aura", "Postictal phase", "Neuralgia"],a:1,e:"Migraine aura consists of transient neurological symptoms such as visual disturbances preceding the headache phase."},
  {q:"A 30-year-old patient with migraine seeks treatment for acute attacks. Which medication is commonly used as first-line therapy for aborting migraine attacks?",o:["Sumatriptan", "Carbamazepine", "Diazepam", "Haloperidol"],a:0,e:"Triptans such as sumatriptan are serotonin receptor agonists used to abort acute migraine attacks by reducing neurovascular inflammation."},
  {q:"A patient reports mild bilateral headaches occurring almost daily, without nausea or photophobia, and symptoms worsen during stressful workdays. Which factor most commonly contributes to this headache type?",o:["Muscle tension and stress", "Vascular inflammation", "Intracranial tumor", "Severe infection"],a:0,e:"Tension headaches are often triggered by psychological stress and muscle contraction in the scalp and neck muscles."},
  {q:"A 45-year-old man presents with recurrent unilateral headaches accompanied by tearing of the eye and drooping eyelid. These symptoms strongly suggest involvement of which system?",o:["Sympathetic nervous system", "Autonomic nervous system", "Somatic sensory system", "Motor system"],a:1,e:"Cluster headaches are associated with autonomic symptoms such as lacrimation, ptosis, and nasal congestion due to trigeminal-autonomic activation."},
  {q:"A patient with frequent migraine attacks asks about preventive treatment. Which medication is commonly used for migraine prophylaxis?",o:["Propranolol", "Amoxicillin", "Diazepam", "Haloperidol"],a:0,e:"Beta-blockers like propranolol are commonly used for migraine prophylaxis, helping reduce attack frequency."},
  {q:"A 34-year-old woman develops sudden severe “worst headache of her life” accompanied by neck stiffness and vomiting. Which condition must be urgently excluded?",o:["Migraine headache", "Tension headache", "Subarachnoid hemorrhage", "Sinusitis"],a:2,e:"Sudden severe headache with neck stiffness suggests subarachnoid hemorrhage, a neurological emergency requiring immediate evaluation."},
  {q:"A patient experiences headaches that worsen when bending forward and are associated with nasal congestion and facial pressure. Which type of headache is most likely?",o:["Sinus headache", "Migraine headache", "Cluster headache", "Tension headache"],a:0,e:"Sinus headaches are associated with facial pressure, nasal congestion, and worsening pain with head movement."},
  {q:"A 29-year-old woman with migraine experiences headaches triggered by certain foods such as chocolate and red wine. Which mechanism explains these triggers?",o:["Increased dopamine release", "Neurovascular activation", "Muscle contraction", "Spinal cord compression"],a:1,e:"Migraine involves activation of trigeminovascular pathways and release of vasoactive neuropeptides."},
  {q:"A patient with cluster headache receives oxygen therapy during an attack. What is the primary therapeutic effect of oxygen in this condition?",o:["Reduces intracranial pressure", "Constricts cerebral blood vessels", "Enhances serotonin release", "Blocks dopamine receptors"],a:1,e:"High-flow oxygen helps abort cluster headache attacks by causing cerebral vasoconstriction and reducing trigeminal activation."},
  {q:"A patient complains of throbbing unilateral headache associated with sensitivity to light and sound lasting several hours. Which symptom is most characteristic of migraine?",o:["Photophobia", "Fever", "Nasal discharge", "Facial numbness"],a:0,e:"Photophobia and phonophobia are classic associated features of migraine headaches."},
  {q:"A patient with chronic headaches reports using analgesics daily for several months. Recently the headaches have become more frequent and resistant to treatment. Which diagnosis should be considered?",o:["Medication overuse headache", "Migraine aura", "Neuralgia", "Cluster headache"],a:0,e:"Frequent use of analgesics can lead to rebound headaches known as medication overuse headache."},
  {q:"A patient describes headaches occurring after prolonged computer work with neck stiffness and scalp tenderness. Which mechanism is most likely responsible?",o:["Trigeminal nerve compression", "Pericranial muscle contraction", "Intracranial hemorrhage", "Infection"],a:1,e:"Tension headaches often result from muscle tension in scalp and neck muscles."},
  {q:"A patient with migraine reports visual aura followed by headache. Which neurotransmitter system plays a major role in migraine pathophysiology?",o:["Serotonin", "Dopamine", "Acetylcholine", "Glycine"],a:0,e:"Migraine involves serotonergic dysregulation and trigeminovascular activation, explaining the efficacy of triptans."},
  {q:"A 50-year-old patient develops progressive headaches worse in the morning and associated with vomiting. What serious cause must be excluded?",o:["Brain tumor", "Migraine", "Tension headache", "Neuralgia"],a:0,e:"Morning headache with vomiting may indicate raised intracranial pressure due to intracranial mass."},
  {q:"A patient complains of unilateral headache associated with scalp tenderness and visual disturbance in an elderly age group. Which diagnosis must be considered urgently?",o:["Temporal arteritis", "Migraine", "Sinusitis", "Tension headache"],a:0,e:"Giant cell arteritis causes headache with visual symptoms and scalp tenderness and requires urgent treatment."},
  {q:"A patient with migraine is advised to maintain regular sleep patterns and avoid triggers. Which management principle does this represent?",o:["Preventive lifestyle modification", "Surgical therapy", "Emergency management", "Diagnostic evaluation"],a:0,e:"Lifestyle modifications such as adequate sleep and trigger avoidance help prevent migraine attacks."},
  {q:"A patient presents with severe unilateral orbital headache lasting about 30 minutes with ipsilateral tearing and restlessness. Which behavior is typical during cluster headache attacks?",o:["Prefers to lie quietly in dark room", "Becomes restless and agitated", "Sleeps deeply", "Experiences paralysis"],a:1,e:"Unlike migraine patients, individuals with cluster headaches are often restless and unable to remain still during attacks."},
  {q:"A 27-year-old woman presents with recurrent unilateral throbbing headaches lasting 6–12 hours, accompanied by nausea and sensitivity to light and sound. She reports that the pain worsens with routine physical activity. Which pathophysiological mechanism most strongly contributes to this headache type?",o:["Cortical spreading depression with trigeminovascular activation", "Increased cerebrospinal fluid production", "Demyelination of cranial nerves", "Brainstem ischemia"],a:0,e:"Migraine is believed to involve cortical spreading depression followed by activation of the trigeminovascular system, leading to release of inflammatory neuropeptides and vasodilation."},
  {q:"A 36-year-old patient experiences daily dull bilateral headaches described as pressure across the forehead. The pain is not aggravated by physical activity and there is no nausea. Which distinguishing feature helps differentiate this headache from migraine?",o:["Presence of photophobia", "Bilateral pressing quality without nausea", "Throbbing character of pain", "Visual aura"],a:1,e:"Tension-type headaches are characterized by bilateral pressure-like pain without nausea or vomiting, unlike migraine which is often throbbing and associated with systemic symptoms."},
  {q:"A 33-year-old patient presents with sudden severe headache accompanied by vomiting and neck stiffness. CT scan shows blood in the subarachnoid space. Which symptom in the clinical history most strongly suggested this diagnosis initially?",o:["Gradual onset headache", "Dull bilateral headache", "“Worst headache of life” sudden onset", "Headache relieved by sleep"],a:2,e:"A sudden thunderclap headache is a classic warning sign of subarachnoid hemorrhage and requires immediate evaluation."},
  {q:"A 42-year-old patient with cluster headaches experiences attacks lasting about 45 minutes, often occurring at the same time every night for several weeks. Which hypothalamic function most likely explains this periodicity?",o:["Regulation of circadian rhythm", "Control of motor reflexes", "Visual processing", "Cerebellar coordination"],a:0,e:"Cluster headaches show circadian periodicity linked to hypothalamic dysfunction, which regulates biological rhythms."},
  {q:"A patient with migraine aura develops transient visual disturbances including zigzag lines and blind spots before the headache phase begins. Which cortical region is most likely responsible for these symptoms?",o:["Occipital cortex", "Frontal cortex", "Cerebellum", "Brainstem"],a:0,e:"Visual aura occurs due to cortical spreading depression beginning in the occipital cortex, affecting visual processing."},
  {q:"A 38-year-old man complains of unilateral headache associated with tearing of the eye, nasal congestion, and eyelid drooping. These symptoms are mediated through which cranial nerve pathway?",o:["Trigeminal nerve pathway", "Optic nerve pathway", "Facial nerve pathway", "Hypoglossal nerve pathway"],a:0,e:"Cluster headaches involve activation of trigeminal-autonomic reflex pathways, producing pain and autonomic symptoms."},
  {q:"A 50-year-old patient reports chronic headaches that worsen gradually over months and are associated with personality changes and morning vomiting. Which red flag feature most strongly suggests secondary headache?",o:["Gradual progressive worsening", "Bilateral pain", "Relief with analgesics", "Occasional photophobia"],a:0,e:"Progressive headaches with neurological changes suggest intracranial pathology such as tumor or raised intracranial pressure."},
  {q:"A 29-year-old migraine patient notes that headaches frequently occur just before menstruation. Which hormonal change is most responsible for this trigger?",o:["Decrease in estrogen levels", "Increase in progesterone", "Increase in cortisol", "Decrease in prolactin"],a:0,e:"Menstrual migraines are associated with falling estrogen levels, which influence serotonergic pathways involved in migraine."},
  {q:"A patient with cluster headache receives high-flow oxygen during an acute attack. What is the most likely mechanism of benefit?",o:["Reduction of trigeminal autonomic activation", "Increase in intracranial pressure", "Blockade of dopamine receptors", "Stimulation of parasympathetic activity"],a:0,e:"Oxygen therapy likely reduces trigeminal nerve activity and cerebral vasodilation, rapidly relieving cluster headache attacks."},
  {q:"A patient with tension-type headache asks about non-pharmacological management strategies. Which approach is most beneficial for reducing attack frequency?",o:["Stress management and relaxation techniques", "High caffeine intake", "Strict bed rest", "Frequent analgesic use"],a:0,e:"Tension headaches are strongly related to stress and muscle tension, so relaxation therapy and stress reduction are effective preventive strategies."},
  {q:"A patient presents with headache associated with fever, neck stiffness, and photophobia. Which diagnosis should be urgently considered?",o:["Migraine", "Meningitis", "Cluster headache", "Tension headache"],a:1,e:"Headache with fever and neck stiffness suggests meningeal irritation, which requires urgent evaluation for meningitis."},
  {q:"A 46-year-old patient complains of sudden sharp stabbing pain in the face triggered by chewing and talking. Which condition best explains this symptom?",o:["Migraine", "Cluster headache", "Trigeminal neuralgia", "Sinus headache"],a:2,e:"Trigeminal neuralgia produces brief electric shock-like facial pain triggered by stimulation of the trigeminal nerve distribution."},
  {q:"A patient experiences headaches associated with visual aura and nausea several times per month. Which preventive medication class is frequently used when attacks are frequent?",o:["Beta blockers", "Antibiotics", "Antihistamines", "Anticoagulants"],a:0,e:"Beta blockers such as propranolol help reduce migraine frequency by modulating vascular and adrenergic activity."},
  {q:"A patient with migraine reports that bright lights and loud sounds worsen the headache. Which term describes sensitivity to sound?",o:["Photophobia", "Hyperacusis", "Phonophobia", "Dysphasia"],a:2,e:"Phonophobia refers to increased sensitivity to sound, a common associated symptom of migraine."},
  {q:"A 60-year-old patient develops new-onset headache with jaw pain while chewing and tenderness over the scalp. ESR is markedly elevated. What is the most likely diagnosis?",o:["Migraine", "Temporal arteritis", "Tension headache", "Sinusitis"],a:1,e:"Giant cell arteritis causes headache, jaw claudication, scalp tenderness, and high ESR, and may lead to vision loss if untreated."},
  {q:"A patient complains of headache that worsens when coughing or bending forward and is associated with facial pressure. Which condition is most consistent with this presentation?",o:["Migraine", "Sinusitis-related headache", "Cluster headache", "Tension headache"],a:1,e:"Sinus headaches are characterized by facial pressure and worsening pain with head movement or bending."},
  {q:"A migraine patient asks why triptans relieve headache symptoms. What is their primary pharmacological action?",o:["Serotonin receptor agonism causing cranial vasoconstriction", "Dopamine receptor blockade", "GABA receptor stimulation", "Histamine receptor blockade"],a:0,e:"Triptans activate 5-HT1B/1D receptors, leading to vasoconstriction of intracranial vessels and inhibition of trigeminal nerve signaling."},
  {q:"A patient reports headaches occurring every afternoon after skipping meals. Which trigger is most likely responsible?",o:["Hypoglycemia", "Hypercalcemia", "Hypertension", "Hyperthyroidism"],a:0,e:"Skipping meals can lead to low blood glucose levels, which may trigger headaches or migraine attacks in susceptible individuals."},
  {q:"A patient with migraine experiences transient numbness in the hand followed by headache. Which type of aura does this represent?",o:["Visual aura", "Sensory aura", "Motor aura", "Auditory aura"],a:1,e:"Sensory aura may present as tingling or numbness in limbs, preceding the migraine headache phase."},
  {q:"A patient with recurrent headaches is advised to keep a headache diary documenting triggers, frequency, and duration of attacks. What is the main purpose of this strategy?",o:["Confirm diagnosis immediately", "Identify triggers and guide preventive therapy", "Replace imaging studies", "Eliminate need for medication"],a:1,e:"A headache diary helps identify patterns, triggers, and treatment responses, assisting clinicians in optimizing preventive management."},
  {q:"A 67-year-old man with long-standing hypertension suddenly develops right-sided weakness and difficulty speaking while watching television. The symptoms reach maximum intensity within minutes. Which type of stroke most commonly presents with this sudden focal neurological deficit?",o:["Ischemic stroke", "Hemorrhagic stroke", "Subdural hematoma", "Brain tumor"],a:0,e:"Most strokes are ischemic, resulting from arterial occlusion causing abrupt loss of blood supply to brain tissue and rapid neurological deficits."},
  {q:"Which of the following best describes a transient ischemic attack (TIA)?",o:["Neurological deficit lasting more than 24 hours", "Temporary focal neurological deficit without permanent infarction", "Chronic progressive neurological decline", "Seizure activity without recovery"],a:1,e:"A TIA causes transient cerebral ischemia with symptoms resolving within 24 hours, often within minutes, and no permanent infarction."},
  {q:"A 72-year-old patient develops sudden weakness of the right arm and leg with deviation of the mouth to the left side. Which cerebral artery territory is most likely involved?",o:["Middle cerebral artery", "Posterior cerebral artery", "Basilar artery", "Vertebral artery"],a:0,e:"The middle cerebral artery (MCA) supplies motor areas controlling the face and upper limbs and is the most common site of ischemic stroke."},
  {q:"Which investigation should be performed first in a patient presenting with suspected acute stroke?",o:["CT scan of the brain", "Lumbar puncture", "EEG", "Carotid ultrasound"],a:0,e:"A non-contrast CT scan is the first investigation to differentiate ischemic from hemorrhagic stroke before treatment."},
  {q:"A 60-year-old woman suddenly develops severe headache, vomiting, and loss of consciousness. CT scan reveals intracerebral bleeding. Which type of stroke does this represent?",o:["Ischemic stroke", "Hemorrhagic stroke", "Lacunar infarction", "Transient ischemic attack"],a:1,e:"Hemorrhagic stroke occurs due to rupture of cerebral blood vessels, often presenting with headache and decreased consciousness."},
  {q:"A patient presents with sudden loss of vision in the left visual field of both eyes after a stroke. Which brain region is most likely affected?",o:["Occipital lobe", "Frontal lobe", "Cerebellum", "Brainstem"],a:0,e:"The occipital cortex processes vision; infarction here causes visual field defects such as homonymous hemianopia."},
  {q:"Which of the following is the most important modifiable risk factor for stroke?",o:["Hypertension", "Gender", "Genetic predisposition", "Age"],a:0,e:"Chronic hypertension damages cerebral vessels and is the most significant modifiable risk factor for stroke."},
  {q:"A patient suddenly develops vertigo, dysarthria, and ataxia following vascular occlusion. Which circulation is most likely involved?",o:["Anterior circulation", "Posterior circulation", "Coronary circulation", "Peripheral circulation"],a:1,e:"Posterior circulation strokes affect the brainstem and cerebellum, producing vertigo, ataxia, and cranial nerve deficits."},
  {q:"Which imaging modality is most sensitive for detecting early ischemic stroke?",o:["MRI with diffusion-weighted imaging", "Plain skull X-ray", "CT angiography only", "Ultrasound"],a:0,e:"Diffusion-weighted MRI detects early ischemic changes within minutes of infarction."},
  {q:"A patient with suspected stroke arrives within 2 hours of symptom onset. CT scan shows no hemorrhage. Which treatment may be considered to restore blood flow?",o:["Intravenous thrombolysis with alteplase", "Immediate antibiotics", "Corticosteroid therapy", "Antipsychotic medication"],a:0,e:"IV alteplase (tPA) can dissolve clots if given within the therapeutic time window for ischemic stroke."},
  {q:"A 70-year-old man develops sudden inability to understand spoken language and produces meaningless speech. Motor power remains intact. Which cortical area is most likely affected?",o:["Broca’s area", "Wernicke’s area", "Occipital cortex", "Cerebellum"],a:1,e:"Wernicke’s area injury produces receptive aphasia with fluent but meaningless speech and impaired comprehension."},
  {q:"A patient develops right-sided facial weakness sparing the forehead along with right arm weakness after a stroke. What type of lesion most likely explains this pattern?",o:["Upper motor neuron lesion", "Lower motor neuron lesion", "Peripheral nerve injury", "Neuromuscular junction defect"],a:0,e:"Central lesions spare forehead muscles due to bilateral cortical innervation of the upper facial muscles."},
  {q:"A patient develops sudden dizziness, difficulty swallowing, and hoarseness of voice following a stroke affecting the lateral medulla. Which syndrome is most consistent with these findings?",o:["Brown-Sequard syndrome", "Wallenberg syndrome", "Horner syndrome", "Parkinson syndrome"],a:1,e:"Lateral medullary infarction causes Wallenberg syndrome, presenting with dysphagia, vertigo, and cranial nerve deficits."},
  {q:"A patient develops weakness of the right arm and face with preserved leg strength. Which artery territory is most likely involved?",o:["Middle cerebral artery", "Anterior cerebral artery", "Posterior cerebral artery", "Basilar artery"],a:0,e:"MCA strokes affect face and upper limb motor areas, while ACA strokes mainly affect the legs."},
  {q:"Which type of stroke results from occlusion of small penetrating arteries and produces small deep infarcts?",o:["Lacunar stroke", "Hemorrhagic stroke", "Embolic stroke", "Subarachnoid hemorrhage"],a:0,e:"Lacunar strokes occur due to small vessel disease, often related to hypertension."},
  {q:"A patient with atrial fibrillation suddenly develops left-sided weakness. What is the most likely mechanism of stroke in this patient?",o:["Cardioembolic stroke", "Lacunar infarction", "Intracranial hemorrhage", "Vasculitis"],a:0,e:"Atrial fibrillation can produce cardiac emboli that travel to cerebral arteries, causing ischemic stroke."},
  {q:"Which clinical sign suggests brainstem stroke rather than cortical stroke?",o:["Aphasia", "Hemiplegia", "Cranial nerve deficits with crossed findings", "Visual field defect"],a:2,e:"Brainstem lesions often produce ipsilateral cranial nerve deficits with contralateral motor or sensory deficits."},
  {q:"A patient presents with sudden severe headache and loss of consciousness. CT scan reveals blood in the subarachnoid space. What is the most common cause?",o:["Ruptured berry aneurysm", "Carotid stenosis", "Lacunar infarction", "Brain tumor"],a:0,e:"Subarachnoid hemorrhage most commonly results from rupture of saccular (berry) aneurysms."},
  {q:"Which medication is commonly used to prevent recurrent ischemic stroke in patients without atrial fibrillation?",o:["Aspirin", "Haloperidol", "Diazepam", "Morphine"],a:0,e:"Aspirin acts as an antiplatelet agent, reducing platelet aggregation and preventing thrombus formation."},
  {q:"A patient with stroke develops spasticity and hyperreflexia weeks after the event. What is the most likely explanation?",o:["Upper motor neuron damage", "Peripheral nerve injury", "Muscle disease", "Neuromuscular junction disorder"],a:0,e:"Chronic stroke may produce spasticity due to loss of inhibitory corticospinal control."},
  {q:"A patient presents with inability to speak but can understand language and follow commands. Which aphasia is present?",o:["Wernicke’s aphasia", "Broca’s aphasia", "Global aphasia", "Conduction aphasia"],a:1,e:"Broca’s aphasia causes non-fluent speech with preserved comprehension due to damage to the dominant frontal lobe."},
  {q:"Which investigation evaluates carotid artery stenosis in patients with ischemic stroke?",o:["Carotid Doppler ultrasound", "EEG", "Lumbar puncture", "Skull X-ray"],a:0,e:"Carotid Doppler identifies atherosclerotic narrowing in carotid arteries, an important stroke risk factor."},
  {q:"A patient develops contralateral weakness and sensory loss with preserved consciousness following a small deep infarct in the internal capsule. What type of stroke is this?",o:["Lacunar stroke", "Hemorrhagic stroke", "Subarachnoid hemorrhage", "Brain tumor"],a:0,e:"Lacunar infarcts in the internal capsule produce pure motor or sensory deficits without cortical signs."},
  {q:"A patient with stroke suddenly develops inability to recognize objects despite intact vision. Which deficit is present?",o:["Aphasia", "Apraxia", "Agnosia", "Ataxia"],a:2,e:"Agnosia refers to inability to recognize objects despite normal sensory function, often due to parietal or temporal lobe damage."},
  {q:"A patient with stroke affecting the cerebellum presents with gait instability and poor coordination. Which symptom best describes this deficit?",o:["Ataxia", "Aphasia", "Hemianopia", "Apraxia"],a:0,e:"Cerebellar stroke commonly causes ataxia, dysmetria, and balance problems."},
  {q:"Which intervention is most important in preventing recurrent stroke after an ischemic event?",o:["Control of risk factors such as hypertension and diabetes", "Complete bed rest", "Antibiotic therapy", "Sedative medications"],a:0,e:"Long-term stroke prevention focuses on managing modifiable risk factors including hypertension, diabetes, and smoking."},
  {q:"A patient with left hemispheric stroke develops difficulty reading and writing but retains speech. Which cortical function is most likely affected?",o:["Language processing", "Motor coordination", "Vision only", "Balance"],a:0,e:"Dominant hemisphere strokes often affect language-related cortical functions such as reading and writing."},
  {q:"A patient with posterior cerebral artery infarction develops loss of vision in the contralateral visual field. What is this condition called?",o:["Diplopia", "Homonymous hemianopia", "Strabismus", "Myopia"],a:1,e:"PCA strokes affecting the occipital cortex cause contralateral homonymous visual field loss."},
  {q:"Which complication commonly develops after severe stroke due to prolonged immobility?",o:["Deep vein thrombosis", "Asthma", "Kidney stones", "Diabetes"],a:0,e:"Immobilized stroke patients are at risk of venous thrombosis due to reduced mobility and venous stasis."},
  {q:"A patient with stroke undergoes physiotherapy soon after stabilization. What is the main goal of early rehabilitation?",o:["Restore lost neurological function and improve independence", "Eliminate all neurological damage", "Replace medication therapy", "Prevent diagnostic procedures"],a:0,e:"Early rehabilitation promotes neuroplasticity, functional recovery, and independence in daily activities after stroke."},
  {q:"A 66-year-old man suddenly develops weakness of the left leg more than the arm, along with mild behavioral changes and urinary urgency. Brain imaging reveals an infarct in the medial surface of the frontal lobe. Which cerebral artery territory is most likely affected?",o:["Middle cerebral artery", "Posterior cerebral artery", "Anterior cerebral artery", "Basilar artery"],a:2,e:"The anterior cerebral artery (ACA) supplies the medial frontal and parietal lobes, which control contralateral lower limb motor function. Infarction often produces leg weakness and behavioral changes."},
  {q:"Which of the following best describes the pathophysiology of ischemic stroke?",o:["Rupture of cerebral artery causing bleeding", "Obstruction of cerebral blood flow leading to neuronal ischemia", "Infection of brain tissue", "Degeneration of cortical neurons"],a:1,e:"Ischemic stroke occurs when arterial occlusion reduces oxygen and glucose supply, leading to neuronal injury and infarction."},
  {q:"A patient with atrial fibrillation presents with sudden right-sided paralysis and aphasia. Brain imaging confirms a large cortical infarct. Which mechanism most likely caused the stroke?",o:["Lipid deposition in small arteries", "Cardiac embolus traveling to cerebral circulation", "Autoimmune vasculitis", "Cerebral aneurysm rupture"],a:1,e:"Atrial fibrillation can lead to formation of thrombi in the atria, which may embolize to cerebral arteries and cause sudden ischemic stroke."},
  {q:"A 58-year-old patient develops sudden double vision, difficulty speaking, and weakness affecting both sides of the body. Which vascular structure is most likely involved?",o:["Basilar artery", "Middle cerebral artery", "Anterior cerebral artery", "Internal carotid artery"],a:0,e:"The basilar artery supplies the brainstem, and its occlusion can cause bilateral neurological deficits, cranial nerve dysfunction, and impaired consciousness."},
  {q:"Which clinical sign most strongly suggests hemorrhagic stroke rather than ischemic stroke?",o:["Sudden hemiplegia", "Severe headache with vomiting", "Aphasia", "Visual field loss"],a:1,e:"Hemorrhagic stroke often presents with sudden severe headache, vomiting, and decreased consciousness, reflecting raised intracranial pressure."},
  {q:"A patient arrives at the emergency department with suspected stroke. The physician emphasizes rapid treatment because neurons die quickly during ischemia. What concept explains this urgency?",o:["Neuroplasticity principle", "“Time is brain” concept", "Neurotransmitter depletion theory", "Cortical inhibition theory"],a:1,e:"During ischemic stroke, millions of neurons are lost every minute, so rapid diagnosis and treatment are essential to preserve brain tissue."},
  {q:"A patient with stroke affecting the dominant hemisphere develops inability to repeat words despite fluent speech and good comprehension. Which type of aphasia is most consistent with this presentation?",o:["Broca’s aphasia", "Wernicke’s aphasia", "Conduction aphasia", "Global aphasia"],a:2,e:"Conduction aphasia results from damage to the arcuate fasciculus connecting Broca’s and Wernicke’s areas, causing impaired repetition with relatively preserved comprehension."},
  {q:"Which medication class is commonly prescribed to prevent cardioembolic stroke in patients with atrial fibrillation?",o:["Anticoagulants", "Antibiotics", "Antidepressants", "Antihistamines"],a:0,e:"Anticoagulants such as warfarin or direct oral anticoagulants prevent thrombus formation in atrial fibrillation and reduce embolic stroke risk."},
  {q:"A patient develops sudden inability to coordinate voluntary movements after a cerebellar infarct. Which neurological sign would most likely be observed during examination?",o:["Spastic paralysis", "Hyperreflexia", "Dysmetria during finger–nose testing", "Loss of language comprehension"],a:2,e:"Cerebellar damage causes ataxia and dysmetria, meaning inaccurate movement when performing coordination tests."},
  {q:"A patient recovering from stroke is advised to begin early physiotherapy and occupational therapy. What is the primary neurological principle supporting early rehabilitation?",o:["Reduction of cerebral blood flow", "Neuroplasticity and functional reorganization", "Inhibition of neurotransmitters", "Prevention of infection"],a:1,e:"After stroke, the brain can reorganize neural pathways through neuroplasticity, allowing rehabilitation to improve motor and functional recovery."},
  {q:"A 64-year-old man presents with gradually progressive slowness of movement, resting tremor in the hands, and muscular rigidity. His symptoms improve with levodopa therapy. Which neurotransmitter deficiency is primarily responsible for this disorder?",o:["Acetylcholine", "Serotonin", "Dopamine", "GABA"],a:2,e:"Parkinson’s disease results from degeneration of dopaminergic neurons in the substantia nigra, leading to dopamine deficiency in the basal ganglia."},
  {q:"Which pathological change is most characteristic of Parkinson’s disease?",o:["Beta-amyloid plaques", "Demyelination of neurons", "Degeneration of Purkinje cells", "Lewy body formation"],a:3,e:"Lewy bodies composed of alpha-synuclein aggregates are characteristic pathological findings in Parkinson’s disease."},
  {q:"A 58-year-old patient presents with resting tremor, rigidity, and bradykinesia. Which brain structure is primarily affected in Parkinsonism?",o:["Substantia nigra", "Hippocampus", "Cerebellum", "Occipital cortex"],a:0,e:"Parkinsonism results from degeneration of neurons in the substantia nigra pars compacta, reducing dopamine levels."},
  {q:"A patient with Parkinson’s disease demonstrates reduced facial expression and decreased spontaneous blinking. Which clinical term describes this feature?",o:["Dyskinesia", "Masked facies", "Ataxia", "Aphasia"],a:1,e:"Masked facies refers to reduced facial expression due to rigidity of facial muscles in Parkinson’s disease."},
  {q:"Which of the following is the most common initial symptom of Parkinson’s disease?",o:["Resting tremor", "Seizures", "Severe headache", "Visual loss"],a:0,e:"A resting tremor (“pill-rolling” tremor) is often the earliest symptom noticed in Parkinson’s disease."},
  {q:"A patient with Parkinson’s disease has difficulty initiating movement and walks with short shuffling steps. What is this gait abnormality called?",o:["Ataxic gait", "Festinating gait", "Spastic gait", "Hemiplegic gait"],a:1,e:"Parkinsonian gait is characterized by short, rapid, shuffling steps and difficulty initiating movement."},
  {q:"A patient with Parkinsonism develops involuntary choreiform movements after prolonged levodopa therapy. What is this complication called?",o:["Dyskinesia", "Aphasia", "Myoclonus", "Spasticity"],a:0,e:"Long-term levodopa therapy may cause involuntary movements known as levodopa-induced dyskinesia."},
  {q:"Which of the following disorders is characterized by degeneration of upper and lower motor neurons?",o:["Multiple sclerosis", "Huntington disease", "Amyotrophic lateral sclerosis", "Parkinson disease"],a:2,e:"ALS is a motor neuron disease involving progressive degeneration of both upper and lower motor neurons."},
  {q:"A patient presents with progressive muscle weakness, fasciculations, and hyperreflexia. Sensory examination is normal. Which diagnosis is most consistent with these findings?",o:["Multiple sclerosis", "Amyotrophic lateral sclerosis", "Myasthenia gravis", "Peripheral neuropathy"],a:1,e:"ALS presents with muscle weakness, fasciculations, and mixed UMN and LMN signs without sensory loss."},
  {q:"Which clinical feature is most characteristic of lower motor neuron involvement in motor neuron disease?",o:["Spasticity", "Hyperreflexia", "Fasciculations", "Babinski sign"],a:2,e:"Lower motor neuron degeneration causes muscle wasting and fasciculations."},
  {q:"Multiple sclerosis is primarily characterized by which pathological process?",o:["Neuronal apoptosis", "Demyelination in the central nervous system", "Peripheral nerve degeneration", "Muscle fiber destruction"],a:1,e:"MS involves immune-mediated destruction of myelin in CNS white matter, producing neurological deficits."},
  {q:"Which of the following populations is most commonly affected by multiple sclerosis?",o:["Elderly men", "Middle-aged women", "Children under 5 years", "Elderly women over 80"],a:1,e:"MS most commonly affects young to middle-aged women, typically between ages 20–40."},
  {q:"A patient with multiple sclerosis experiences episodes of visual loss with pain on eye movement. Which condition explains this symptom?",o:["Optic neuritis", "Glaucoma", "Retinal detachment", "Cataract"],a:0,e:"Optic neuritis is a common early manifestation of multiple sclerosis, causing painful vision loss."},
  {q:"A patient with MS reports weakness and numbness that worsen in hot weather. Which phenomenon explains this?",o:["Uhthoff phenomenon", "Kernig sign", "Babinski response", "Trousseau sign"],a:0,e:"Increased temperature temporarily worsens conduction in demyelinated nerves, worsening MS symptoms."},
  {q:"Which diagnostic investigation is most useful for confirming multiple sclerosis?",o:["MRI of brain and spinal cord", "CT abdomen", "X-ray skull", "EEG"],a:0,e:"MRI detects demyelinating plaques in the CNS, a hallmark of MS."},
  {q:"A 22-year-old patient with MS develops double vision due to impaired coordination of eye movements. Which sign is typical in MS?",o:["Internuclear ophthalmoplegia", "Nystagmus only", "Cataract", "Retinal hemorrhage"],a:0,e:"Demyelination of the medial longitudinal fasciculus causes internuclear ophthalmoplegia."},
  {q:"Wilson’s disease results from abnormal accumulation of which substance in the body?",o:["Iron", "Copper", "Calcium", "Sodium"],a:1,e:"Wilson’s disease is caused by impaired copper metabolism leading to accumulation in liver and brain."},
  {q:"A patient with Wilson’s disease develops tremor, psychiatric symptoms, and liver dysfunction. Which ocular sign is most characteristic?",o:["Kayser–Fleischer ring", "Arcus senilis", "Papilledema", "Retinal detachment"],a:0,e:"Copper deposition in the cornea produces Kayser–Fleischer rings, a key diagnostic sign."},
  {q:"Which gene mutation is responsible for Wilson’s disease?",o:["ATP7B gene", "HTT gene", "APP gene", "SOD1 gene"],a:0,e:"Wilson’s disease is caused by mutations in ATP7B, affecting copper transport and excretion."},
  {q:"Which medication is commonly used to treat Wilson’s disease by chelating copper?",o:["Penicillamine", "Diazepam", "Haloperidol", "Levodopa"],a:0,e:"Penicillamine binds copper and promotes urinary excretion, reducing copper accumulation."},
  {q:"Huntington’s disease is inherited in which pattern?",o:["Autosomal dominant", "Autosomal recessive", "X-linked recessive", "Mitochondrial"],a:0,e:"Huntington’s disease is caused by autosomal dominant inheritance of the HTT gene mutation."},
  {q:"The primary pathological change in Huntington’s disease occurs in which brain region?",o:["Cerebellum", "Substantia nigra", "Caudate nucleus", "Hippocampus"],a:2,e:"Degeneration of the caudate nucleus and basal ganglia leads to movement and cognitive symptoms."},
  {q:"A patient with Huntington’s disease presents with involuntary dance-like movements of the limbs. What is this symptom called?",o:["Chorea", "Tremor", "Rigidity", "Dystonia"],a:0,e:"Chorea refers to rapid, irregular, involuntary movements typical of Huntington’s disease."},
  {q:"Which genetic mutation causes Huntington’s disease?",o:["CAG trinucleotide repeat expansion", "CGG repeat expansion", "Deletion of chromosome 21", "Insertion of adenine repeats"],a:0,e:"Huntington’s disease results from expanded CAG repeats in the HTT gene."},
  {q:"A patient with Huntington’s disease develops progressive cognitive decline and psychiatric symptoms. Which symptom often appears early in the disease?",o:["Depression and personality changes", "Visual loss", "Severe muscle weakness", "Loss of sensation"],a:0,e:"Psychiatric symptoms such as depression and irritability often precede motor symptoms."},
  {q:"Which neurotransmitter imbalance contributes to motor symptoms in Huntington’s disease?",o:["Decreased GABA activity", "Increased acetylcholine", "Increased serotonin", "Decreased dopamine"],a:0,e:"Degeneration of GABAergic neurons in the basal ganglia contributes to chorea and movement abnormalities."},
  {q:"A patient with Parkinson’s disease develops postural instability and frequent falls during disease progression. Which brain circuit is primarily involved?",o:["Basal ganglia motor circuit", "Limbic system", "Visual cortex", "Auditory cortex"],a:0,e:"Parkinson’s disease disrupts basal ganglia circuits responsible for motor control and posture."},
  {q:"Which symptom is most characteristic of upper motor neuron involvement in motor neuron disease?",o:["Muscle wasting", "Fasciculations", "Hyperreflexia", "Hypotonia"],a:2,e:"Upper motor neuron damage produces hyperreflexia and spasticity, often seen in ALS."},
  {q:"A patient with multiple sclerosis experiences episodes of neurological deficits followed by partial recovery. What pattern of disease progression does this describe?",o:["Relapsing-remitting course", "Progressive neurodegeneration only", "Acute monophasic illness", "Chronic stable disease"],a:0,e:"The most common form of MS is relapsing-remitting, characterized by attacks followed by recovery."},
  {q:"Which environmental factor has been associated with increased risk of multiple sclerosis?",o:["Vitamin D deficiency", "High calcium intake", "Excess iron", "High sodium intake"],a:0,e:"Low vitamin D levels and reduced sunlight exposure are associated with higher MS risk."},
  {q:"A patient with Wilson’s disease develops neurological symptoms due to copper accumulation in which brain region?",o:["Basal ganglia", "Occipital cortex", "Cerebellum only", "Brainstem only"],a:0,e:"Copper deposition particularly affects the basal ganglia, producing movement disorders."},
  {q:"Which clinical sign is most typical of Parkinson’s disease during physical examination?",o:["Resting tremor with “pill-rolling” movement", "Rapid choreiform movements", "Severe muscle atrophy", "Sudden paralysis"],a:0,e:"The pill-rolling resting tremor is a classic sign of Parkinson’s disease."},
  {q:"A patient with ALS gradually develops difficulty swallowing and speaking. Which term describes this complication?",o:["Bulbar palsy", "Cerebellar ataxia", "Sensory neuropathy", "Optic neuritis"],a:0,e:"Bulbar involvement in ALS causes dysphagia and dysarthria due to cranial nerve motor neuron degeneration."},
  {q:"Which medication is most commonly used as first-line therapy for Parkinson’s disease symptoms?",o:["Levodopa", "Penicillamine", "Interferon beta", "Haloperidol"],a:0,e:"Levodopa increases dopamine levels in the brain, improving motor symptoms of Parkinson’s disease."},
  {q:"Which neurological disorder is characterized by both movement abnormalities and progressive cognitive decline due to basal ganglia degeneration?",o:["Multiple sclerosis", "Huntington’s disease", "Motor neuron disease", "Wilson’s disease"],a:1,e:"Huntington’s disease causes chorea, psychiatric symptoms, and progressive dementia due to basal ganglia degeneration."},
  {q:"A patient with MS develops numbness and weakness in the legs along with urinary urgency. Which spinal cord pathology explains these symptoms?",o:["Demyelinating plaques", "Tumor metastasis", "Vascular aneurysm", "Bacterial infection"],a:0,e:"MS lesions in the spinal cord produce sensory deficits, weakness, and bladder dysfunction."},
  {q:"Which disease is caused by impaired copper excretion leading to toxic accumulation in tissues?",o:["Huntington’s disease", "Wilson’s disease", "Parkinson’s disease", "ALS"],a:1,e:"Wilson’s disease results from defective copper metabolism due to ATP7B mutation."},
  {q:"A patient with Huntington’s disease asks about prognosis. What is the typical disease course?",o:["Acute reversible illness", "Slowly progressive neurodegenerative disorder", "Intermittent self-limited episodes", "Fully curable condition"],a:1,e:"Huntington’s disease is a progressive inherited neurodegenerative disorder leading to motor, cognitive, and psychiatric decline."},
  {q:"Which symptom combination is most typical of Parkinson’s disease?",o:["Tremor, rigidity, and bradykinesia", "Chorea, dementia, and seizures", "Spastic paralysis and sensory loss", "Ataxia and vision loss"],a:0,e:"The classic triad of Parkinson’s disease includes resting tremor, rigidity, and bradykinesia."},
  {q:"A patient with motor neuron disease develops progressive respiratory weakness leading to difficulty breathing. Which muscle group is primarily affected causing this complication?",o:["Diaphragm and respiratory muscles", "Facial muscles", "Extraocular muscles", "Hand muscles only"],a:3,e:"In advanced ALS, degeneration of motor neurons supplying respiratory muscles such as the diaphragm leads to respiratory failure."},
  {q:"A 72-year-old hospitalized patient suddenly develops confusion, fluctuating attention, visual hallucinations, and a disturbed sleep–wake cycle within 24 hours of admission. Which clinical feature most strongly distinguishes delirium from dementia?",o:["Memory impairment", "Personality change", "Progressive cognitive decline", "Fluctuating level of consciousness"],a:3,e:"Delirium is characterized by acute onset and fluctuating disturbance in attention and consciousness. Dementia usually develops gradually and does not show rapid fluctuation in awareness."},
  {q:"Which neurotransmitter imbalance is most strongly implicated in the pathophysiology of delirium?",o:["Decreased acetylcholine with increased dopamine", "Increased serotonin and decreased GABA", "Increased glutamate and decreased norepinephrine", "Increased acetylcholine and decreased dopamine"],a:0,e:"Delirium is associated with cholinergic deficiency and dopaminergic excess. Many drugs with anticholinergic effects can precipitate delirium, especially in elderly patients."},
  {q:"A 70-year-old patient with Alzheimer’s disease develops progressive memory impairment beginning with inability to recall recent events. Which brain structure is most critically involved in early Alzheimer’s disease?",o:["Cerebellum", "Hippocampus", "Brainstem", "Occipital cortex"],a:1,e:"Early Alzheimer’s disease involves degeneration of the hippocampus and medial temporal lobe, leading to impaired episodic memory and difficulty forming new memories."},
  {q:"Which pathological hallmark is most characteristic of Alzheimer’s disease?",o:["Lewy bodies", "Multiple lacunar infarcts", "Beta-amyloid plaques and neurofibrillary tangles", "Demyelinating plaques"],a:2,e:"Alzheimer’s disease is defined by extracellular beta-amyloid plaques and intracellular tau neurofibrillary tangles, causing progressive neuronal loss and cortical atrophy."},
  {q:"A patient develops cognitive decline following multiple strokes and demonstrates stepwise deterioration with focal neurological deficits. Which diagnosis is most likely?",o:["Lewy body dementia", "Frontotemporal dementia", "Alzheimer’s disease", "Vascular dementia"],a:3,e:"Vascular dementia results from repeated cerebrovascular insults, leading to stepwise cognitive decline and focal neurological signs."},
  {q:"A 22-year-old patient collapses with generalized tonic stiffening followed by rhythmic jerking of limbs and postictal confusion. Which seizure type best explains this presentation?",o:["Myoclonic seizure", "Generalized tonic-clonic seizure", "Absence seizure", "Focal aware seizure"],a:1,e:"Generalized tonic-clonic seizures involve tonic muscle contraction followed by clonic jerking, loss of consciousness, and a postictal state of confusion and fatigue."},
  {q:"A patient with epilepsy experiences sudden brief episodes of staring with impaired awareness lasting about 10 seconds and immediate recovery afterward. EEG shows generalized 3-Hz spike-and-wave discharges. Which seizure type is most consistent with this presentation?",o:["Tonic seizure", "Myoclonic seizure", "Absence seizure", "Focal motor seizure"],a:2,e:"Absence seizures present with brief staring spells, impaired awareness, and immediate recovery, typically associated with 3-Hz spike-and-wave EEG activity."},
  {q:"A patient with migraine reports seeing flashing lights and zigzag lines before the headache begins. What is this phenomenon called?",o:["Photophobia", "Vertigo", "Hyperalgesia", "Aura"],a:3,e:"Migraine aura consists of transient neurological symptoms, often visual disturbances such as scintillating scotomas preceding the headache."},
  {q:"Which headache disorder is characterized by severe unilateral periorbital pain associated with lacrimation and nasal congestion?",o:["Cluster headache", "Migraine", "Tension headache", "Sinus headache"],a:0,e:"Cluster headache presents with severe unilateral orbital pain and autonomic symptoms such as lacrimation, rhinorrhea, and conjunctival injection."},
  {q:"A patient develops sudden right-sided weakness and expressive aphasia due to infarction of the dominant hemisphere. Which cerebral artery is most likely affected?",o:["Anterior cerebral artery", "Posterior cerebral artery", "Basilar artery", "Middle cerebral artery"],a:3,e:"The middle cerebral artery supplies the motor cortex for face and upper limb and language centers (Broca’s area) in the dominant hemisphere."},
  {q:"A patient with Parkinsonism presents with resting tremor, rigidity, and bradykinesia. Degeneration of which brain structure is primarily responsible?",o:["Substantia nigra", "Hippocampus", "Thalamus", "Cerebellum"],a:0,e:"Parkinson’s disease results from degeneration of dopaminergic neurons in the substantia nigra, disrupting basal ganglia motor circuits."},
  {q:"Which motor symptom is most characteristic of Parkinson’s disease?",o:["Ataxia", "Myoclonus", "Resting tremor", "Chorea"],a:2,e:"The classic triad of Parkinson’s disease includes resting tremor, rigidity, and bradykinesia, reflecting dopaminergic depletion in basal ganglia pathways."},
  {q:"A patient with progressive muscle weakness shows both upper motor neuron signs (spasticity, hyperreflexia) and lower motor neuron signs (fasciculations, muscle wasting). Which disease is most likely?",o:["Peripheral neuropathy", "Amyotrophic lateral sclerosis", "Multiple sclerosis", "Myasthenia gravis"],a:1,e:"ALS affects both upper and lower motor neurons, producing combined signs such as spasticity, hyperreflexia, fasciculations, and progressive muscle wasting."},
  {q:"A young adult develops episodes of visual loss, limb weakness, and sensory disturbances with partial recovery between episodes. Which neurological disorder is most likely?",o:["Multiple sclerosis", "Wilson’s disease", "Huntington’s disease", "Parkinson’s disease"],a:0,e:"Multiple sclerosis is an autoimmune demyelinating disorder characterized by relapsing-remitting neurological deficits separated in time and space."},
  {q:"Which pathological process underlies the neurological deficits in multiple sclerosis?",o:["Degeneration of basal ganglia", "Demyelination of CNS neurons", "Copper deposition", "Vascular infarction"],a:1,e:"Multiple sclerosis involves immune-mediated destruction of myelin in the central nervous system, slowing nerve conduction and producing neurological deficits."},
  {q:"Wilson’s disease results from abnormal metabolism and accumulation of which metal in the body?",o:["Calcium", "Magnesium", "Copper", "Iron"],a:2,e:"Wilson’s disease results from mutation in the ATP7B gene, causing impaired copper excretion and accumulation in liver, brain, and cornea."},
  {q:"Which ocular sign is most characteristic of Wilson’s disease?",o:["Retinal hemorrhage", "Kayser–Fleischer rings", "Papilledema", "Cataracts"],a:1,e:"Kayser–Fleischer rings are brownish copper deposits in the corneal Descemet membrane, visible on slit-lamp examination."},
  {q:"Huntington’s disease is inherited in which genetic pattern?",o:["Autosomal dominant", "Autosomal recessive", "Mitochondrial inheritance", "X-linked recessive"],a:0,e:"Huntington’s disease is an autosomal dominant disorder caused by expansion of CAG trinucleotide repeats in the HTT gene."},
  {q:"Which movement disorder is most characteristic of Huntington’s disease?",o:["Rigidity", "Tremor", "Dystonia", "Chorea"],a:3,e:"Huntington’s disease produces chorea, characterized by rapid, irregular, involuntary movements due to degeneration of basal ganglia neurons."},
  {q:"Early psychiatric manifestations of Huntington’s disease most commonly include which of the following?",o:["Severe amnesia", "Visual hallucinations only", "Acute delirium", "Depression and personality changes"],a:3,e:"Psychiatric symptoms such as depression, irritability, and personality changes often appear early in Huntington’s disease and may precede motor symptoms by years."},
];